diff --git a/src/__tests__/welcomepage.test.js b/src/__tests__/welcomepage.test.js
new file mode 100644
--- /dev/null
+++ b/src/__tests__/welcomepage.test.js
@@ -0,0 +1,143 @@
+/**
+ * @jest-environment jsdom
+ */
+import React from "react";
+import { render, screen } from "@testing-library/react";
+import { MemoryRouter } from "react-router-dom";
+
+// Mock framer-motion
+jest.mock("framer-motion", () => {
+  const React = require("react");
+  return {
+    motion: new Proxy(
+      {},
+      {
+        get: (_, tag) =>
+          React.forwardRef(({ children, ...props }, ref) => {
+            const validProps = {};
+            Object.keys(props).forEach((key) => {
+              if (
+                !["initial", "animate", "exit", "transition", "whileHover", "whileInView", "variants", "style"].includes(key)
+              ) {
+                validProps[key] = props[key];
+              }
+            });
+            return React.createElement(tag, { ...validProps, ref }, children);
+          }),
+      }
+    ),
+    AnimatePresence: ({ children }) => React.createElement(React.Fragment, null, children),
+    useScroll: () => ({ scrollYProgress: { get: () => 0, onChange: () => () => {} } }),
+    useTransform: () => ({ get: () => 1, onChange: () => () => {} }),
+  };
+});
+
+// Mock react-icons
+jest.mock("react-icons/fa", () => {
+  const React = require("react");
+  return new Proxy(
+    {},
+    {
+      get: (_, name) => (props) => React.createElement("svg", { "data-testid": name, ...props }),
+    }
+  );
+});
+
+import WelcomePage from "../pages/welcomepage";
+
+const renderPage = () => {
+  return render(
+    <MemoryRouter>
+      <WelcomePage />
+    </MemoryRouter>
+  );
+};
+
+describe("WelcomePage", () => {
+  describe("navigation sections exist", () => {
+    it("renders the features section with correct id", () => {
+      const { container } = renderPage();
+      const section = container.querySelector("#features");
+      expect(section).not.toBeNull();
+    });
+
+    it("renders the showcase section with correct id", () => {
+      const { container } = renderPage();
+      const section = container.querySelector("#showcase");
+      expect(section).not.toBeNull();
+    });
+
+    it("renders the testimonials section with correct id", () => {
+      const { container } = renderPage();
+      const section = container.querySelector("#testimonials");
+      expect(section).not.toBeNull();
+    });
+
+    it("renders a contact section that the nav anchor resolves to", () => {
+      const { container } = renderPage();
+      const section = container.querySelector("section#contact");
+      expect(section).not.toBeNull();
+    });
+
+    it("contact section contains a Get in Touch heading", () => {
+      const { container } = renderPage();
+      const section = container.querySelector("#contact");
+      expect(section).not.toBeNull();
+      const heading = section.querySelector("h2");
+      expect(heading).not.toBeNull();
+      expect(heading.textContent).toMatch(/get in touch/i);
+    });
+
+    it("contact section is placed before the footer", () => {
+      const { container } = renderPage();
+      const contact = container.querySelector("#contact");
+      const footer = container.querySelector("footer");
+      expect(contact).not.toBeNull();
+      expect(footer).not.toBeNull();
+      // contact should come before footer in DOM order
+      const comparison = contact.compareDocumentPosition(footer);
+      // Node.DOCUMENT_POSITION_FOLLOWING = 4
+      expect(comparison & 4).toBeTruthy();
+    });
+  });
+
+  describe("existing features still render", () => {
+    it("renders all six feature cards", () => {
+      renderPage();
+      expect(screen.getByText("Smart Ticketing")).toBeTruthy();
+      expect(screen.getByText("Omnichannel Support")).toBeTruthy();
+      expect(screen.getByText("Knowledge Base")).toBeTruthy();
+      expect(screen.getByText("Team Collaboration")).toBeTruthy();
+      expect(screen.getByText("Advanced Analytics")).toBeTruthy();
+      expect(screen.getByText("Community Forums")).toBeTruthy();
+    });
+
+    it("renders testimonial content", () => {
+      renderPage();
+      expect(screen.getByText(/Depika Bansal/i)).toBeTruthy();
+    });
+
+    it("renders the product showcase tabs", () => {
+      renderPage();
+      expect(screen.getByText("Ticket List")).toBeTruthy();
+      expect(screen.getByText("Ticket View")).toBeTruthy();
+      expect(screen.getByText("Dashboard")).toBeTruthy();
+    });
+
+    it("renders nav links for all four sections", () => {
+      const { container } = renderPage();
+      const navLinks = container.querySelectorAll('a[href^="#"]');
+      const hrefs = Array.from(navLinks).map((a) => a.getAttribute("href"));
+      expect(hrefs).toContain("#features");
+      expect(hrefs).toContain("#showcase");
+      expect(hrefs).toContain("#testimonials");
+      expect(hrefs).toContain("#contact");
+    });
+
+    it("renders the hero stats section", () => {
+      renderPage();
+      expect(screen.getByText("99.9%")).toBeTruthy();
+      expect(screen.getByText("Uptime")).toBeTruthy();
+    });
+  });
+});
